typedef struct APO_REG_PROPERTIES {
CLSID    clsid;   APO_FLAG Flags;
WCHAR    szFriendlyName[256];   WCHAR    szCopyrightInfo[256];
UINT32   u32MajorVersion;   UINT32   u32MinorVersion;
UINT32   u32MinInputConnections;   UINT32   u32MaxInputConnections;   UINT32   u32MinOutputConnections;   UINT32   u32MaxOutputConnections;   UINT32   u32MaxInstances;
UINT32   u32NumAPOInterfaces;
IID      iidAPOInterfaceList[1];
} APO_REG_PROPERTIES, *PAPO_REG_PROPERTIES;
成员 clsid
此 APO 的类 ID。 Flags
此 APO 的标志。 此参数是 APO_FLAG 类型的枚举常量。 szFriendlyName[256]
此 APO 的友好名称。 这是最大长度为 256 的字符串。 szCopyrightInfo[256]
此 APO 的版权信息。 这是最大长度为 256 的字符串。
u32MajorVersion
此 APO 的主版本号。 u32MinorVersion
此 APO 的次要版本号。 u32MinInputConnections
此 APO 的最小输入连接数。 u32MaxInputConnections
此 APO 的最大输入连接数。 u32MinOutputConnections 此 APO 的最小输出连接数。 u32MaxOutputConnections 此 APO 的最大输出连接数。 u32MaxInstances
此 APO 的最大实例数。 u32NumAPOInterfaces 此 APO 的接口数。 iidAPOInterfaceList[1]
typedef struct APOInitBaseStruct {
UINT32 cbSize;   CLSID  clsid;
} APOInitBaseStruct;
成员 cbSize
